163	/// Read an env-file value or None if absent. Mirrors the helpers in rbtdrk
164	/// and rbtdrp — kept local to avoid cross-module coupling.
165	fn rbtdro_read_env_value(path: &Path, key: &str) -> Option<String> {
166	    let content = std::fs::read_to_string(path).ok()?;
167	    let prefix = format!("{}=", key);
168	    for line in content.lines() {
169	        let trimmed = line.trim_start();
170	        if trimmed.starts_with('#') {
171	            continue;
172	        }
173	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
174	            return Some(rest.to_string());
175	        }
176	    }
177	    None
178	}
