346	/// Pull a docker image. Used by the graft case to ensure the source image
347	/// is locally resolvable before the BURE_TWEAK-overridden ordain.
348	fn rbtdro_docker_pull(image_ref: &str) -> Result<(), String> {
349	    let output = std::process::Command::new("docker")
350	        .args(["pull", image_ref])
351	        .output()
