364	/// Write a value into a vessel's rbrv.env. Same atomic-rename pattern as
365	/// rbtdro_drive_hallmark, but targeting the vessel's regime file rather than
366	/// a nameplate's. Returns Err if the variable line is not found.
367	fn rbtdro_write_vessel_env(
368	    root: &Path,
369	    vessel_dir: &str,
370	    var_name: &str,
371	    value: &str,
372	) -> Result<(), String> {
373	    let rbrv_path = root.join(vessel_dir).join(RBTDRO_VESSEL_RBRV_FILE);
374	    let file = std::fs::File::open(&rbrv_path)
375	        .map_err(|e| format!("open rbrv.env for {}: {}", vessel_dir, e))?;
376	
377	    let lines: Vec<String> = BufReader::new(file)
378	        .lines()
379	        .collect::<Result<_, _>>()
380	        .map_err(|e| format!("read rbrv.env for {}: {}", vessel_dir, e))?;
381	
382	    let prefix = format!("{}=", var_name);
383	    let mut found = false;
384	    let rewritten: Vec<String> = lines
385	        .into_iter()
386	        .map(|line| {
387	            if line.starts_with(&prefix) {
388	                found = true;
389	                format!("{}={}", var_name, value)
390	            } else {
391	                line
392	            }
393	        })
394	        .collect();
395	
396	    if !found {
397	        return Err(format!(
398	            "variable {} not found in {}/rbrv.env",
399	            var_name, vessel_dir
400	        ));
401	    }
402	
403	    let tmp_path = rbrv_path.with_extension("env.write_tmp");
404	    {
405	        let mut tmp = std::fs::File::create(&tmp_path)
406	            .map_err(|e| format!("create tmp rbrv.env for {}: {}", vessel_dir, e))?;
407	        for line in &rewritten {
408	            writeln!(tmp, "{}", line)
409	                .map_err(|e| format!("write tmp rbrv.env for {}: {}", vessel_dir, e))?;
410	        }
411	    }
412	    std::fs::rename(&tmp_path, &rbrv_path)
413	        .map_err(|e| format!("atomic replace rbrv.env for {}: {}", vessel_dir, e))?;
414	    Ok(())
415	}
