417	/// Drive a hallmark value into a nameplate's rbrn.env. Mirrors the
418	/// zrbob_drive_hallmark substitution logic from rbob_bottle.sh: load file
419	/// lines, replace the matching `VAR=*` line with the new value, atomic rename.
420	/// Returns Err if the variable line is not found (hard fail — configuration error).
421	fn rbtdro_drive_hallmark(
422	    root: &Path,
423	    nameplate: &str,
424	    var_name: &str,
425	    hallmark: &str,
426	) -> Result<(), String> {
427	    let rbrn_path = root.join(".rbk").join(nameplate).join("rbrn.env");
428	    let file = std::fs::File::open(&rbrn_path)
429	        .map_err(|e| format!("open rbrn.env for {}: {}", nameplate, e))?;
430	
431	    let lines: Vec<String> = BufReader::new(file)
432	        .lines()
433	        .collect::<Result<_, _>>()
434	        .map_err(|e| format!("read rbrn.env for {}: {}", nameplate, e))?;
435	
436	    let prefix = format!("{}=", var_name);
437	    let mut found = false;
438	    let rewritten: Vec<String> = lines
439	        .into_iter()
440	        .map(|line| {
441	            if line.starts_with(&prefix) {
442	                found = true;
443	                format!("{}={}", var_name, hallmark)
444	            } else {
445	                line
446	            }
447	        })
448	        .collect();
449	
450	    if !found {
451	        return Err(format!(
452	            "variable {} not found in .rbk/{}/rbrn.env",
453	            var_name, nameplate
454	        ));
455	    }
456	
457	    let tmp_path = root
458	        .join(".rbk")
459	        .join(nameplate)
460	        .join("rbrn.env.drive_tmp");
461	    {
462	        let mut tmp = std::fs::File::create(&tmp_path)
463	            .map_err(|e| format!("create tmp rbrn.env for {}: {}", nameplate, e))?;
464	        for line in &rewritten {
465	            writeln!(tmp, "{}", line)
466	                .map_err(|e| format!("write tmp rbrn.env for {}: {}", nameplate, e))?;
467	        }
468	    }
469	    std::fs::rename(&tmp_path, &rbrn_path)
470	        .map_err(|e| format!("atomic replace rbrn.env for {}: {}", nameplate, e))?;
471	    Ok(())
472	}
