474	/// Auto-commit helper. Checks git status --porcelain; if the working tree is
475	/// clean, returns Ok without committing. Otherwise runs `git add -A` then
476	/// `git commit -m <message>`. Theurge launches from project root so no
477	/// explicit current_dir is needed.
478	fn rbtdro_git_commit(message: &str) -> Result<(), rbtdre_Verdict> {
479	    let status = std::process::Command::new("git")
480	        .args(["status", "--porcelain"])
481	        .output()
482	        .map_err(|e| {
483	            rbtdre_Verdict::Fail(format!("git status --porcelain exec failed: {}", e))
484	        })?;
485	    if !status.status.success() {
486	        return Err(rbtdre_Verdict::Fail(format!(
487	            "git status --porcelain exited {}",
488	            status.status.code().unwrap_or(-1)
489	        )));
490	    }
491	    let porcelain = String::from_utf8_lossy(&status.stdout);
492	    if porcelain.trim().is_empty() {
493	        // Nothing to commit — clean tree is not an error.
494	        return Ok(());
495	    }
496	
497	    let add = std::process::Command::new("git")
498	        .args(["add", "-A"])
499	        .output()
500	        .map_err(|e| rbtdre_Verdict::Fail(format!("git add -A exec failed: {}", e)))?;
501	    if !add.status.success() {
502	        return Err(rbtdre_Verdict::Fail(format!(
503	            "git add -A exited {}: {}",
504	            add.status.code().unwrap_or(-1),
505	            String::from_utf8_lossy(&add.stderr).trim()
506	        )));
507	    }
508	
509	    let commit = std::process::Command::new("git")
510	        .args(["commit", "-m", message])
511	        .output()
512	        .map_err(|e| rbtdre_Verdict::Fail(format!("git commit exec failed: {}", e)))?;
513	    if !commit.status.success() {
514	        return Err(rbtdre_Verdict::Fail(format!(
515	            "git commit exited {}: {}",
516	            commit.status.code().unwrap_or(-1),
517	            String::from_utf8_lossy(&commit.stderr).trim()
518	        )));
519	    }
520	    Ok(())
521	}
