586	/// Inscribe the depot-wide reliquary toolchain. Captures the reliquary
587	/// stamp from BURV fact, persists it to the fixture scratch file, then
588	/// yokes the stamp into all ordain-side vessels in one pass and auto-commits.
589	fn rbtdro_onboarding_inscribe_reliquary(dir: &Path) -> rbtdre_Verdict {
590	    let probe = rbtdrb_Probe {
591	        name: "governor RBRA present",
592	        check: rbtdro_probe_governor_rbra,
593	        remediation: "rerun canonical-establish (rbtdrk_governor_mantle) before this fixture",
594	    };
595	    if let Err(v) = rbtdrb_assert(&probe) {
596	        return v;
597	    }
598	    rbtdrc_with_ctx(|ctx| rbtdro_onboarding_inscribe_reliquary_impl(ctx, dir))
599	}
600	
601	fn rbtdro_onboarding_inscribe_reliquary_impl(
602	    ctx: &mut rbtdri_Context,
603	    dir: &Path,
604	) -> rbtdre_Verdict {
605	    let result = match rbtdro_invoke_logged(
606	        ctx,
607	        RBTDRM_COLOPHON_INSCRIBE_RELIQUARY,
608	        &[],
609	        &[],
610	        dir,
611	        "inscribe",
612	    ) {
613	        Ok(r) => r,
614	        Err(e) => return rbtdre_Verdict::Fail(format!("inscribe invocation: {}", e)),
615	    };
616	    if result.exit_code != 0 {
617	        return rbtdre_Verdict::Fail(format!(
618	            "inscribe exit {}\n{}",
619	            result.exit_code, result.stderr
620	        ));
621	    }
622	
623	    let stamp = match rbtdri_read_burv_fact(&result, RBTDRC_FACT_RELIQUARY) {
624	        Ok(s) => s,
625	        Err(e) => return rbtdre_Verdict::Fail(format!("read reliquary fact: {}", e)),
626	    };
627	    let _ = std::fs::write(dir.join("reliquary-stamp.txt"), &stamp);
628	
629	    // Yoke stamp into all ordain-side vessels in one pass.
630	    for vessel_dir in RBTDRO_YOKE_VESSEL_DIRS {
631	        let sigil = vessel_dir.rsplit('/').next().unwrap_or(vessel_dir);
632	        let label = format!("{}-{}", RBTDRO_OPERATION_YOKE, sigil);
633	        if let Err(v) = rbtdro_yoke(ctx, dir, &stamp, sigil, &label) {
634	            return v;
635	        }
636	    }
637	
638	    // Commit the rbrv.env changes for all yoked vessels.
639	    if let Err(v) = rbtdro_git_commit(
640	        &format!("inscribe-reliquary: {} stamp into all ordain-side vessels", RBTDRO_OPERATION_YOKE),
641	    ) {
642	        return v;
643	    }
644	
645	    rbtdre_Verdict::Pass
646	}
