813	    if let Err(v) = rbtdro_enshrine(ctx, dir, forge_sigil, "enshrine-upstream") {
814	        return v;
815	    }
816	    // Commit before ordain-forge: ordain has clean-tree precondition.
817	    if let Err(v) = rbtdro_git_commit(
818	        "ordain-airgap: enshrine upstream rust base into forge vessel",
819	    ) {
820	        return v;
821	    }
822	
823	    // Capture the forge hallmark — it becomes the airgap-bottle's base via
824	    // a hallmark-namespace locator (mechanism (c)).
825	    let forge_hallmark = match rbtdro_ordain_capture(
826	        ctx,
827	        dir,
828	        RBTDRO_VESSEL_DIR_AIRGAP_FORGE,
829	        &[],
830	        "ordain-forge",
831	    ) {
832	        Ok(h) => h,
833	        Err(v) => return v,
834	    };
