836	    // Write the hallmark-base locator into airgap-bottle's rbrv.env. The slot
837	    // points at the forge image inside its hallmark subtree; conjure resolves
838	    // this locator to a full GAR ref at airgap-bottle build time.
839	    let airgap_anchor = format!(
840	        "{}/{}/{}:{}",
841	        RBTDRO_GAR_CATEGORY_HALLMARKS,
