849	        RBTDRO_AIRGAP_BASE_ANCHOR_VAR,
850	        &airgap_anchor,
851	    ) {
852	        return rbtdre_Verdict::Fail(format!("write airgap-bottle anchor: {}", e));
853	    }
854	    let _ = std::fs::write(dir.join("airgap-anchor.txt"), &airgap_anchor);
855	
856	    // Commit the locator write before ordain-airgap: ordain has clean-tree
857	    // precondition. The forge hallmark's existence in GAR is established by
858	    // ordain-forge's success above — no separate enshrine validation step.
859	    if let Err(v) = rbtdro_git_commit(
860	        "ordain-airgap: write forge-hallmark locator into airgap-bottle base anchor",
861	    ) {
862	        return v;
863	    }
