865	    let airgap_hallmark = match rbtdro_ordain_capture(
866	        ctx,
867	        dir,
868	        RBTDRO_VESSEL_DIR_AIRGAP_BOTTLE,
869	        &[],
870	        "ordain-airgap",
871	    ) {
872	        Ok(h) => h,
873	        Err(v) => return v,
874	    };
875	
876	    for nameplate in RBTDRO_CONSUMERS_AIRGAP_BOTTLE {
877	        if let Err(e) =
878	            rbtdro_drive_hallmark(&root, nameplate, RBTDRO_HALLMARK_VAR_BOTTLE, &airgap_hallmark)
879	        {
880	            return rbtdre_Verdict::Fail(format!(
881	                "drive airgap hallmark into {}: {}",
882	                nameplate, e
883	            ));
884	        }
885	    }
886	
887	    if let Err(v) =
888	        rbtdro_git_commit("ordain-airgap: airgap-bottle hallmark + propagate to moriah")
