939	    {
940	        return v;
941	    }
942	
943	    rbtdre_Verdict::Pass
944	}
945	
946	/// Pull the graft source image, then ordain rbev-graft-demo with a
947	/// BURE_TWEAK overriding RBRV_GRAFT_IMAGE in-process. No consumers —
948	/// graft-demo is terminal.
949	fn rbtdro_onboarding_ordain_graft(dir: &Path) -> rbtdre_Verdict {
950	    let probe = rbtdrb_Probe {
951	        name: "reliquary stamp captured",
952	        check: rbtdro_probe_reliquary_stamp,
953	        remediation: "rerun rbtdro_onboarding_inscribe_reliquary before this case",
954	    };
955	    if let Err(v) = rbtdrb_assert(&probe) {
956	        return v;
957	    }
958	    rbtdrc_with_ctx(|ctx| rbtdro_onboarding_ordain_graft_impl(ctx, dir))
959	}
960	
961	fn rbtdro_onboarding_ordain_graft_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
962	    if let Err(e) = rbtdro_docker_pull(RBTDRO_GRAFT_SOURCE_IMAGE) {
963	        return rbtdre_Verdict::Fail(format!(
964	            "docker pull {}: {}",
965	            RBTDRO_GRAFT_SOURCE_IMAGE, e
966	        ));
967	    }
968	    let extra_env: &[(&str, &str)] = &[
969	        ("BURE_TWEAK_NAME", RBTDRO_GRAFT_TWEAK_NAME),
970	        ("BURE_TWEAK_VALUE", RBTDRO_GRAFT_SOURCE_IMAGE),
971	    ];
972	    let hallmark = match rbtdro_ordain_capture(
973	        ctx,
974	        dir,
975	        RBTDRO_VESSEL_DIR_GRAFT,
976	        extra_env,
977	        "ordain-graft",
978	    ) {
979	        Ok(h) => h,
980	        Err(v) => return v,
981	    };
982	    let _ = hallmark; // graft-demo is terminal — no consumer propagation
983	
984	    if let Err(v) = rbtdro_git_commit("ordain-graft: graft-demo hallmark") {
985	        return v;
986	    }
987	
988	    rbtdre_Verdict::Pass
989	}
990	
991	// ── Section registry ─────────────────────────────────────────
992	
993	pub static RBTDRO_SECTIONS_ONBOARDING_SEQUENCE: &[rbtdre_Section] = &[rbtdre_Section {
994	    name: "onboarding-arc",
995	    cases: &[
996	        case!(rbtdro_onboarding_inscribe_reliquary),
997	        case!(rbtdro_onboarding_kludge_tadmor),
998	        case!(rbtdro_onboarding_kludge_ccyolo),
999	        case!(rbtdro_onboarding_ordain_conjure),
1000	        case!(rbtdro_onboarding_conjure_srjcl),
1001	        case!(rbtdro_onboarding_ordain_airgap),
1002	        case!(rbtdro_onboarding_ordain_bind),
1003	        case!(rbtdro_onboarding_ordain_graft),
1004	    ],
1005	}];
1006	
1007	pub static RBTDRO_FIXTURE_ONBOARDING_SEQUENCE: rbtdre_Fixture = rbtdre_Fixture {
1008	    name: RBTDRM_FIXTURE_ONBOARDING_SEQUENCE,
1009	    disposition: rbtdre_Disposition::StateProgressing,
1010	    setup: None,
1011	    teardown: None,
1012	    sections: RBTDRO_SECTIONS_ONBOARDING_SEQUENCE,
1013	};
